(()=>{'use strict';
const DESIGN_W=980;
function ensureMeta(){let m=document.querySelector('meta[name="viewport"]');if(!m){m=document.createElement('meta');m.name='viewport';document.head.appendChild(m)}m.content='width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no,viewport-fit=cover'}
function ensureStage(){let s=document.querySelector('.layout-lock-stage');if(s)return s;s=document.createElement('div');s.className='layout-lock-stage';while(document.body.firstChild)s.appendChild(document.body.firstChild);document.body.appendChild(s);return s}
function ensureStyle(){let st=document.getElementById('layout-lock-v258');if(!st){st=document.createElement('style');st.id='layout-lock-v258';st.textContent=`html,body{margin:0!important;padding:0!important;width:100%!important;max-width:none!important;overflow-x:hidden!important;background:#f6f7f8!important}.layout-lock-stage{width:${DESIGN_W}px!important;max-width:none!important;margin:0!important;transform-origin:top left!important;position:relative!important}.topbar{width:${DESIGN_W}px!important;max-width:none!important;margin:0!important;height:56px!important;padding:0 16px!important}.wrap{width:${DESIGN_W}px!important;max-width:none!important;margin:0!important;padding:16px!important}.topGrid{display:grid!important;grid-template-columns:1.1fr .9fr!important;gap:14px!important}.tabs{display:grid!important;grid-template-columns:repeat(5,1fr)!important;gap:10px!important}.filterGrid{display:grid!important;grid-template-columns:1fr 1fr 1fr!important;gap:12px!important}.range{display:grid!important;grid-template-columns:1fr 24px 1fr!important;gap:6px!important}.dash{display:block!important}.searchLine{display:grid!important;grid-template-columns:1fr 360px!important;gap:10px!important}.summaryHead{display:flex!important;align-items:center!important;justify-content:space-between!important}.actions{display:flex!important;gap:8px!important;margin-top:0!important;grid-template-columns:none!important}.summary{display:grid!important;grid-template-columns:repeat(4,1fr)!important;gap:10px!important}.bottomBar{display:flex!important;justify-content:space-between!important}.leftBtns{display:flex!important;gap:8px!important}.tableWrap{overflow:auto!important;-webkit-overflow-scrolling:touch!important}.tbl{min-width:940px!important;font-size:13px!important}.help{display:inline-flex!important;align-items:center!important}.prepBtn{height:34px;border:1px solid #15803d;background:#087b34;color:#fff;border-radius:8px;font-weight:950;padding:0 10px;white-space:nowrap}@media(max-width:99999px){.topGrid{grid-template-columns:1.1fr .9fr!important}.tabs{grid-template-columns:repeat(5,1fr)!important}.filterGrid{grid-template-columns:1fr 1fr 1fr!important}.summary{grid-template-columns:repeat(4,1fr)!important}.searchLine{grid-template-columns:1fr 360px!important}.bottomBar{display:flex!important}.leftBtns{display:flex!important}.actions{display:flex!important}}@media print{html,body,.layout-lock-stage{width:auto!important;max-width:none!important;transform:none!important}.topbar,.wrap{width:auto!important}}`;document.head.appendChild(st)}else if(document.head.lastElementChild!==st){document.head.appendChild(st)}return st}
function scale(){ensureMeta();const s=ensureStage();ensureStyle();const vw=(window.visualViewport&&window.visualViewport.width)||window.innerWidth||DESIGN_W;const sc=Math.min(vw/DESIGN_W,1);s.style.transform=`scale(${sc})`;document.body.style.height=Math.ceil(s.scrollHeight*sc)+'px';document.body.style.minHeight=Math.ceil(s.scrollHeight*sc)+'px'}
function labels(){const t=document.querySelector('.title');if(t)t.textContent='Solomon DOIT Pro V2.5.8';document.title='Solomon DOIT Pro V2.5.8'}
function addPrepButton(){const a=document.querySelector('.actions');if(a&&!document.getElementById('prepPrint')){const b=document.createElement('button');b.id='prepPrint';b.className='prepBtn';b.textContent='เตรียมปริ้น';a.prepend(b)}}
function tick(){ensureStyle();labels();addPrepButton();scale()}
window.addEventListener('resize',tick);window.visualViewport&&window.visualViewport.addEventListener('resize',tick);document.addEventListener('DOMContentLoaded',()=>{tick();setTimeout(tick,150);setTimeout(tick,800);new MutationObserver(()=>setTimeout(tick,0)).observe(document.documentElement,{childList:true,subtree:true});});
})();
